const AWS = require('aws-sdk');
const crypto = require('crypto');

const dynamo = new AWS.DynamoDB.DocumentClient();

const TABLE_NAME = process.env.USERS_TABLE;
const EMAIL_GSI = process.env.EMAIL_GSI || 'email-index';
const PASSWORD_HASH_ALGO = 'sha256';
const PASSWORD_SALT_BYTES = 16;
const PASSWORD_ITERATIONS = 200000;
const PASSWORD_KEYLEN = 32;
const MAX_EMAIL_LEN = 320;
const MIN_PASSWORD_LEN = 8;

function json(statusCode, body, extraHeaders) {
  return {
    statusCode,
    headers: {
      'Content-Type': 'application/json',
      'Access-Control-Allow-Origin': '*',
      'Access-Control-Allow-Headers': 'Content-Type,Authorization',
      'Access-Control-Allow-Methods': 'OPTIONS,POST',
      ...(extraHeaders || {})
    },
    body: JSON.stringify(body || {})
  };
}

function safeJsonParse(str) {
  try {
    return [JSON.parse(str), null];
  } catch (e) {
    return [null, e];
  }
}

function normalizeEmail(email) {
  return String(email || '').trim().toLowerCase();
}

function isValidEmail(email) {
  if (!email || typeof email !== 'string') return false;
  if (email.length < 3 || email.length > MAX_EMAIL_LEN) return false;
  // Simple pragmatic regex for MVP
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(email);
}

function isValidPassword(password) {
  if (!password || typeof password !== 'string') return false;
  if (password.length < MIN_PASSWORD_LEN) return false;
  if (password.length > 1024) return false;
  return true;
}

function pbkdf2Hash(password, salt) {
  const derived = crypto.pbkdf2Sync(password, salt, PASSWORD_ITERATIONS, PASSWORD_KEYLEN, PASSWORD_HASH_ALGO);
  return derived.toString('base64');
}

function nowIso() {
  return new Date().toISOString();
}

function uuid() {
  if (crypto.randomUUID) return crypto.randomUUID();
  return ([1e7]+-1e3+-4e3+-8e3+-1e11).replace(/[018]/g, c =>
    (c ^ crypto.randomBytes(1)[0] & 15 >> c / 4).toString(16)
  );
}

async function getUserByEmail(email) {
  // Prefer GSI query if configured, otherwise fall back to scan (not recommended)
  if (EMAIL_GSI) {
    const res = await dynamo.query({
      TableName: TABLE_NAME,
      IndexName: EMAIL_GSI,
      KeyConditionExpression: '#e = :e',
      ExpressionAttributeNames: { '#e': 'email' },
      ExpressionAttributeValues: { ':e': email },
      Limit: 1
    }).promise();
    return (res.Items && res.Items[0]) || null;
  }

  const res = await dynamo.scan({
    TableName: TABLE_NAME,
    FilterExpression: '#e = :e',
    ExpressionAttributeNames: { '#e': 'email' },
    ExpressionAttributeValues: { ':e': email },
    Limit: 1
  }).promise();
  return (res.Items && res.Items[0]) || null;
}

async function createUser({ email, password }) {
  const userId = uuid();
  const salt = crypto.randomBytes(PASSWORD_SALT_BYTES).toString('base64');
  const hash = pbkdf2Hash(password, Buffer.from(salt, 'base64'));
  const createdAt = nowIso();

  const item = {
    pk: `USER#${userId}`,
    sk: `USER#${userId}`,
    userId,
    email,
    passwordHash: hash,
    passwordSalt: salt,
    passwordAlgo: `pbkdf2-${PASSWORD_HASH_ALGO}`,
    passwordIterations: PASSWORD_ITERATIONS,
    createdAt,
    updatedAt: createdAt
  };

  await dynamo.put({
    TableName: TABLE_NAME,
    Item: item,
    ConditionExpression: 'attribute_not_exists(pk)'
  }).promise();

  return { userId, email, createdAt };
}

exports.handler = async (event) => {
  try {
    if (!TABLE_NAME) return json(500, { message: 'Server misconfigured: USERS_TABLE not set' });

    const method = event.httpMethod || event.requestContext?.http?.method;
    if (method === 'OPTIONS') return json(204, null);
    if (method !== 'POST') return json(405, { message: 'Method Not Allowed' }, { 'Allow': 'OPTIONS, POST' });

    const [body, parseErr] = safeJsonParse(event.body || '{}');
    if (parseErr) return json(400, { message: 'Invalid JSON body' });

    const email = normalizeEmail(body.email);
    const password = body.password;

    if (!isValidEmail(email)) return json(400, { message: 'Invalid email' });
    if (!isValidPassword(password)) return json(400, { message: 'Invalid password' });

    const existing = await getUserByEmail(email);
    if (existing) return json(409, { message: 'Email already registered' });

    const created = await createUser({ email, password });
    return json(201, { userId: created.userId, email: created.email, createdAt: created.createdAt });
  } catch (err) {
    const statusCode = err && err.code === 'ConditionalCheckFailedException' ? 409 : 500;
    return json(statusCode, { message: statusCode === 409 ? 'Email already registered' : 'Internal Server Error' });
  }
};